426	    private void startPollingHelper(EventSourceMapping esm) {
427	        if (esm.getEventSourceArn().contains(":sqs:")) {
428	            poller.startPolling(esm);
429	        } else if (esm.getEventSourceArn().contains(":kinesis:")) {
430	            kinesisPoller.startPolling(esm);
431	        } else if (esm.getEventSourceArn().contains(":dynamodb:")) {
432	            dynamodbStreamsPoller.startPolling(esm);
433	        }
434	    }
