436	    private void stopPollingHelper(EventSourceMapping esm) {
437	        if (esm.getEventSourceArn().contains(":sqs:")) {
438	            poller.stopPolling(esm.getUuid());
439	        } else if (esm.getEventSourceArn().contains(":kinesis:")) {
440	            kinesisPoller.stopPolling(esm.getUuid());
441	        } else if (esm.getEventSourceArn().contains(":dynamodb:")) {
442	            dynamodbStreamsPoller.stopPolling(esm.getUuid());
443	        }
444	    }
