462	    public EventSourceMapping updateEventSourceMapping(String uuid, Map<String, Object> request) {
463	        EventSourceMapping esm = getEventSourceMapping(uuid);
464	
465	        boolean wasEnabled = esm.isEnabled();
466	
467	        if (request.containsKey("BatchSize")) {
468	            esm.setBatchSize(toInt(request.get("BatchSize"), esm.getBatchSize()));
469	        }
470	        if (request.containsKey("Enabled")) {
471	            boolean nowEnabled = !Boolean.FALSE.equals(request.get("Enabled"));
472	            esm.setEnabled(nowEnabled);
473	            esm.setState(nowEnabled ? "Enabled" : "Disabled");
474	        }
475	
476	        esm.setLastModified(System.currentTimeMillis());
477	        esmStore.save(esm);
478	
479	        // Start/stop polling if enabled state changed
480	        if (!wasEnabled && esm.isEnabled()) {
481	            startPollingHelper(esm);
482	        } else if (wasEnabled && !esm.isEnabled()) {
483	            stopPollingHelper(esm);
484	        }
485	
486	        LOG.infov("Updated ESM {0}: batchSize={1} enabled={2}", uuid, esm.getBatchSize(), esm.isEnabled());
487	        return esm;
488	    }
