590	    public LambdaUrlConfig createFunctionUrlConfig(String region, String functionName, String qualifier, Map<String, Object> request) {
591	        LambdaArnUtils.ResolvedFunctionRef ref = resolveWithRegion(region, functionName, qualifier);
592	        functionName = ref.name();
593	        qualifier = ref.qualifier();
594	        LambdaUrlConfig urlConfig = new LambdaUrlConfig();
595	        urlConfig.setAuthType((String) request.getOrDefault("AuthType", "NONE"));
596	        if (request.containsKey("InvokeMode")) {
597	            urlConfig.setInvokeMode((String) request.get("InvokeMode"));
598	        }
599	
600	        String urlId = UUID.nameUUIDFromBytes((region + functionName + (qualifier != null ? qualifier : "")).getBytes()).toString().replace("-", "").substring(0, 32);
601	        String baseHost = config.effectiveBaseUrl().replaceFirst("https?://", "");
602	        String url = String.format("http://%s.lambda-url.%s.%s/", urlId, region, baseHost);
603	        urlConfig.setFunctionUrl(url);
604	
605	        String now = DateTimeFormatter.ISO_INSTANT.format(Instant.now().atOffset(ZoneOffset.UTC));
606	        urlConfig.setCreationTime(now);
607	        urlConfig.setLastModifiedTime(now);
608	
609	        // Handle CORS
610	        @SuppressWarnings("unchecked")
611	        Map<String, Object> corsMap = (Map<String, Object>) request.get("Cors");
612	        if (corsMap != null) {
613	            LambdaUrlConfig.Cors cors = new LambdaUrlConfig.Cors();
614	            cors.setAllowCredentials(Boolean.TRUE.equals(corsMap.get("AllowCredentials")));
615	            cors.setAllowHeaders(toStringArray(corsMap.get("AllowHeaders")));
616	            cors.setAllowMethods(toStringArray(corsMap.get("AllowMethods")));
617	            cors.setAllowOrigins(toStringArray(corsMap.get("AllowOrigins")));
618	            cors.setExposeHeaders(toStringArray(corsMap.get("ExposeHeaders")));
619	            cors.setMaxAge(toInt(corsMap.get("MaxAge"), 0));
620	            urlConfig.setCors(cors);
621	        }
622	
623	        if (qualifier != null && !qualifier.equals("$LATEST")) {
624	            LambdaAlias alias = getAlias(region, functionName, qualifier);
625	            if (alias.getUrlConfig() != null) {
626	                throw new AwsException("ResourceConflictException", "Function URL config already exists for alias: " + qualifier, 409);
627	            }
628	            urlConfig.setFunctionArn(alias.getAliasArn());
629	            alias.setUrlConfig(urlConfig);
630	            if (aliasStore != null) aliasStore.save(region, alias);
631	        } else {
632	            LambdaFunction fn = getFunction(region, functionName);
633	            if (fn.getUrlConfig() != null) {
634	                throw new AwsException("ResourceConflictException", "Function URL config already exists for function: " + functionName, 409);
635	            }
636	            urlConfig.setFunctionArn(fn.getFunctionArn());
637	            fn.setUrlConfig(urlConfig);
638	            functionStore.save(region, fn);
639	        }
640	
641	        LOG.infov("Created Function URL for {0} (qualifier: {1}): {2}", functionName, qualifier, url);
642	        return urlConfig;
643	    }
