729	    public LambdaFunction putFunctionConcurrency(String region, String functionName, Integer reservedConcurrentExecutions) {
730	        if (reservedConcurrentExecutions == null || reservedConcurrentExecutions < 0) {
731	            throw new AwsException("InvalidParameterValueException",
732	                    "ReservedConcurrentExecutions must be a non-negative integer", 400);
733	        }
734	        LambdaFunction fn = getFunction(region, functionName);
735	        String arn = fn.getFunctionArn();
736	        // Serialize limiter update + store save for this function so that two
737	        // concurrent Puts cannot leave the limiter and persisted state out of
738	        // sync, regardless of which call acquires the reservedLock first.
739	        synchronized (lockForConcurrencyOp(arn)) {
740	            Integer previousReserved = null;
741	            boolean limiterUpdated = false;
742	            if (concurrencyLimiter != null) {
743	                previousReserved = concurrencyLimiter.validateAndSetReserved(
744	                        arn, reservedConcurrentExecutions);
745	                limiterUpdated = true;
746	            }
747	            fn.setReservedConcurrentExecutions(reservedConcurrentExecutions);
748	            try {
749	                functionStore.save(region, fn);
750	            } catch (RuntimeException e) {
751	                if (limiterUpdated) {
752	                    concurrencyLimiter.rollbackReservedIfExpected(
753	                            arn, reservedConcurrentExecutions, previousReserved);
754	                }
755	                throw e;
756	            }
757	        }
758	        return fn;
759	    }
