766	    public void deleteFunctionConcurrency(String region, String functionName) {
767	        LambdaFunction fn = getFunction(region, functionName);
768	        String arn = fn.getFunctionArn();
769	        synchronized (lockForConcurrencyOp(arn)) {
770	            Integer previousReserved = null;
771	            boolean limiterCleared = false;
772	            if (concurrencyLimiter != null) {
773	                previousReserved = concurrencyLimiter.clearReserved(arn);
774	                limiterCleared = true;
775	            }
776	            fn.setReservedConcurrentExecutions(null);
777	            try {
778	                functionStore.save(region, fn);
779	            } catch (RuntimeException e) {
780	                if (limiterCleared && previousReserved != null) {
781	                    concurrencyLimiter.rollbackReservedIfExpected(
782	                            arn, null, previousReserved);
783	                }
784	                throw e;
785	            }
786	        }
787	    }
