819	    private void extractZipCode(LambdaFunction fn, String zipFileBase64) {
820	        byte[] zipBytes = Base64.getDecoder().decode(zipFileBase64);
821	        Path codePath = codeStore.getCodePath(fn.getFunctionName());
822	        try {
823	            zipExtractor.extractTo(zipBytes, codePath);
824	            fn.setCodeLocalPath(codePath.toAbsolutePath().normalize().toString());
825	            fn.setCodeSizeBytes(zipBytes.length);
826	
827	            // For file-based runtimes, verify handler file exists (skip Java and .NET which use different handler formats)
828	            if (fn.getRuntime() != null && !fn.getRuntime().startsWith("java") && !fn.getRuntime().startsWith("dotnet")) {
829	                String handlerFile = fn.getHandler().split("\\.")[0];
830	                boolean found = Files.walk(codePath)
831	                        .filter(Files::isRegularFile)
832	                        .anyMatch(p -> {
833	                            String relative = codePath.relativize(p).toString();
834	                            String withoutExt = relative.contains(".")
835	                                    ? relative.substring(0, relative.lastIndexOf('.'))
836	                                    : relative;
837	                            return withoutExt.equals(handlerFile);
838	                        });
839	                if (!found) {
840	                    throw new AwsException("InvalidParameterValueException",
841	                            "Handler file '" + handlerFile + "' not found in deployment package", 400);
842	                }
843	            }
844	        } catch (AwsException e) {
845	            throw e;
846	        } catch (IOException e) {
847	            throw new AwsException("InvalidParameterValueException",
848	                    "Failed to extract deployment package: " + e.getMessage(), 400);
849	        }
850	    }
