855	        }
856	        S3Object obj;
857	        try {
858	            obj = s3Service.getObject(s3Bucket, s3Key);
859	        } catch (Exception e) {
860	            throw new AwsException("InvalidParameterValueException",
861	                    "Unable to fetch code from s3://" + s3Bucket + "/" + s3Key + ": " + e.getMessage(), 400);
862	        }
863	        extractZipCode(fn, Base64.getEncoder().encodeToString(obj.getData()));
