868	    public Map<String, Object> addPermission(String region, String functionName, Map<String, Object> request) {
869	        LambdaFunction fn = getFunction(region, functionName);
870	        String statementId = (String) request.get("StatementId");
871	        if (statementId == null || statementId.isBlank()) {
872	            throw new AwsException("InvalidParameterValueException", "StatementId is required", 400);
873	        }
874	        fn.getPolicies().stream()
875	                .filter(s -> statementId.equals(s.get("Sid")))
876	                .findFirst()
877	                .ifPresent(s -> {
878	                    throw new AwsException("ResourceConflictException",
879	                            "The statement id (" + statementId + ") already exists. Please try again with a new Statement Id.", 409);
880	                });
881	
882	        String principal = (String) request.get("Principal");
883	        String action = (String) request.get("Action");
884	        String sourceArn = (String) request.get("SourceArn");
885	        String sourceAccount = (String) request.get("SourceAccount");
886	
887	        Map<String, Object> statement = new java.util.LinkedHashMap<>();
888	        statement.put("Sid", statementId);
889	        statement.put("Effect", "Allow");
890	        if (principal != null && principal.contains(".")) {
891	            statement.put("Principal", Map.of("Service", principal));
892	        } else if (principal != null && principal.startsWith("arn:")) {
893	            statement.put("Principal", Map.of("AWS", principal));
894	        } else {
895	            statement.put("Principal", principal);
896	        }
897	        statement.put("Action", action);
898	        statement.put("Resource", fn.getFunctionArn());
899	        if (sourceArn != null) {
900	            statement.put("Condition", Map.of("ArnLike", Map.of("AWS:SourceArn", sourceArn)));
901	        } else if (sourceAccount != null) {
902	            statement.put("Condition", Map.of("StringEquals", Map.of("AWS:SourceAccount", sourceAccount)));
903	        }
904	
905	        fn.getPolicies().add(statement);
906	        functionStore.save(region, fn);
907	        LOG.infov("Added permission {0} to function {1}", statementId, functionName);
908	        return statement;
909	    }
