962	    /**
963	     * Resolves a tag-endpoint ARN to a (region, shortName) pair. The Lambda
964	     * tag APIs only accept an unqualified full function ARN; reject partial
965	     * ARNs, bare names, and qualified ARNs.
966	     */
967	    private TagTarget resolveTagTarget(String functionArn) {
968	        if (functionArn == null || functionArn.isBlank()) {
969	            throw new AwsException("InvalidParameterValueException", "Resource ARN is required", 400);
970	        }
971	        if (!functionArn.startsWith("arn:")) {
972	            throw new AwsException("InvalidParameterValueException",
973	                    "Resource ARN must be a full Lambda function ARN: " + functionArn, 400);
974	        }
975	        LambdaArnUtils.ResolvedFunctionRef ref = LambdaArnUtils.resolve(functionArn);
976	        if (ref.qualifier() != null) {
977	            throw new AwsException("InvalidParameterValueException",
978	                    "Tag operations require an unqualified function ARN: " + functionArn, 400);
979	        }
980	        return new TagTarget(ref.region(), ref.name());
981	    }
