983	    private int toInt(Object value, int defaultValue) {
984	        if (value == null) return defaultValue;
985	        if (value instanceof Number n) return n.intValue();
986	        try {
987	            return Integer.parseInt(value.toString());
988	        } catch (NumberFormatException e) {
989	            return defaultValue;
990	        }
991	    }
